+  for (let page = 1; page <= REST_MAX_PAGES; page++) {
+    const url = `${API_BASE}/repos/${repo}/issues?state=all&per_page=${REST_PER_PAGE}&page=${page}&sort=created&direction=desc`;

-    await delay(SEARCH_RATE_LIMIT_DELAY_MS);
